use crate::config::v2::schema::CiConfig;
use std::collections::{HashMap, HashSet};
use std::path::{Path, PathBuf};

fn fixture(name: &str) -> PathBuf {
    crate::codebase::ts_resolver::normalize_path(
        &PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../test-cases/workflow-topology")
            .join(name),
    )
}

fn golden(root: &Path, filename: &str) -> String {
    let path = root.join(filename);
    std::fs::read_to_string(&path)
        .unwrap_or_else(|error| panic!("read {}: {error}", path.display()))
}

fn render(root: &Path, filters: &[&str]) -> String {
    let filters: Vec<String> = filters.iter().map(ToString::to_string).collect();
    let topology = load_workflow_topology(root, &CiConfig::default(), &filters);
    render_workflow_topology_json(&topology).expect("a parsed topology always serializes")
}

fn json(text: &str) -> serde_json::Value {
    serde_json::from_str(text).expect("golden and rendered output are both valid JSON")
}

fn render_mermaid(root: &Path) -> String {
    let topology = load_workflow_topology(root, &CiConfig::default(), &[]);
    render_workflow_topology_mermaid(&topology)
}

