/// Exercises the concurrency-lock rendering path specifically: a
/// workflow-level expression group (its own per-declaration lock) plus two
/// job-level literal groups differing only in case (sharing one lock,
/// since literal groups are keyed case-insensitively).
#[test]
fn mermaid_matches_ts_engine_for_concurrency_locks() {
    let root = fixture("concurrency");
    assert_eq!(render_mermaid(&root), golden(&root, "expected.mmd"));
    assert_eq!(render(&root, &[]), golden(&root, "expected.json"));
}

