/// `serde_yaml`'s and `js-yaml`'s parse-error messages are different
/// libraries' wording for the same malformed-YAML failure, so
/// `malformed-workflow`'s `message` text can never byte-match the TS
/// engine's. Every other field, and every other diagnostic in the same
/// fixture (including the dangling-needs case), still must.
#[test]
fn invalid_fixture_matches_ts_engine_except_malformed_message_text() {
    let root = fixture("invalid");
    let actual = strip_malformed_messages(json(&render(&root, &[])));
    let expected = strip_malformed_messages(json(&golden(&root, "expected.json")));
    assert_eq!(actual, expected);
}

fn strip_malformed_messages(mut value: serde_json::Value) -> serde_json::Value {
    if let Some(diagnostics) = value
        .get_mut("diagnostics")
        .and_then(serde_json::Value::as_array_mut)
    {
        for diagnostic in diagnostics {
            if diagnostic.get("code").and_then(serde_json::Value::as_str)
                == Some("malformed-workflow")
            {
                diagnostic["message"] = serde_json::Value::String("<parser-specific>".to_string());
            }
        }
    }
    value
}

