// ── unit tests: graph_algorithms ────────────────────────────────────────

#[test]
fn scc_finds_a_cycle_and_leaves_isolated_nodes_singleton() {
    let mut adjacency: HashMap<String, HashSet<String>> = HashMap::new();
    adjacency.insert("a".into(), HashSet::from(["b".into()]));
    adjacency.insert("b".into(), HashSet::from(["c".into()]));
    adjacency.insert("c".into(), HashSet::from(["a".into()]));
    adjacency.insert("solo".into(), HashSet::new());

    let mut components = strongly_connected_components(&adjacency);
    components.sort();
    assert_eq!(
        components,
        vec![
            vec!["a".to_string(), "b".to_string(), "c".to_string()],
            vec!["solo".to_string()]
        ]
    );
}

#[test]
fn scc_visits_a_target_only_node_with_no_adjacency_entry() {
    // "b" is never a key in `adjacency`, only ever a target — the
    // algorithm must still visit it (with an implicit empty successor
    // set) rather than panicking or skipping it.
    let mut adjacency: HashMap<String, HashSet<String>> = HashMap::new();
    adjacency.insert("a".into(), HashSet::from(["b".into()]));

    let mut components = strongly_connected_components(&adjacency);
    components.sort();
    assert_eq!(
        components,
        vec![vec!["a".to_string()], vec!["b".to_string()]]
    );
}

// ── unit tests: case_insensitive_lookup ─────────────────────────────────

#[test]
fn case_insensitive_lookup_resolves_missing_ambiguous_and_resolved() {
    let lookup = CaseInsensitiveLookup::new([
        ("Build".to_string(), 1),
        ("build".to_string(), 2),
        ("Test".to_string(), 3),
    ]);

    assert!(matches!(lookup.resolve("nope"), Resolution::Missing));
    assert!(matches!(lookup.resolve("BUILD"), Resolution::Ambiguous));
    match lookup.resolve("test") {
        Resolution::Resolved { key, value } => {
            assert_eq!(key, "Test");
            assert_eq!(*value, 3);
        }
        Resolution::Missing => panic!("expected Resolved, got Missing"),
        Resolution::Ambiguous => panic!("expected Resolved, got Ambiguous"),
    }

    // Only the unambiguous "Test" entry survives into unique_entries().
    let unique: Vec<(&str, i32)> = lookup
        .unique_entries()
        .map(|(key, value)| (key, *value))
        .collect();
    assert_eq!(unique, vec![("Test", 3)]);
}

// ── unit tests: expression_references ───────────────────────────────────

#[test]
fn static_references_is_case_sensitive_and_ignores_quoted_text() {
    // Only the real `needs.` access counts; the quoted lookalike and the
    // differently-cased "Needs." do not.
    let refs = static_references(
        Some("needs.build.result == 'needs.fake' && Needs.other"),
        "needs",
    );
    assert_eq!(refs, vec!["build".to_string()]);
}

#[test]
fn static_references_supports_bracket_access() {
    let refs = static_references(Some("needs['build-job'].result == 'success'"), "needs");
    assert_eq!(refs, vec!["build-job".to_string()]);
}

#[test]
fn static_workflow_output_references_case_insensitive_needs_and_outputs() {
    let refs = static_workflow_output_references(Some("${{ NEEDS.Build.OUTPUTS.value }}"), false);
    assert_eq!(refs.len(), 1);
    assert_eq!(refs[0].call_job_id, "Build");
    assert_eq!(refs[0].output, "value");
}

#[test]
fn static_workflow_output_references_rejects_further_access() {
    // `needs.x.outputs.y.z` has trailing access past the output name, so
    // it isn't a bare output reference.
    let refs = static_workflow_output_references(Some("needs.build.outputs.value.nested"), true);
    assert!(refs.is_empty());
}

#[test]
fn static_workflow_output_references_allow_bare_toggles_delimiter_requirement() {
    let bare = "needs.build.outputs.value";
    assert!(static_workflow_output_references(Some(bare), false).is_empty());
    assert_eq!(static_workflow_output_references(Some(bare), true).len(), 1);
}

#[test]
fn workflow_output_references_scans_nested_scalars_and_bare_conditions() {
    let job: serde_yaml::Value = serde_yaml::from_str(
        r#"
if: needs.build.outputs.ready == 'true'
env:
  NESTED: "${{ needs.other.outputs.value }}"
steps:
  - if: needs.step-job.outputs.x == '1'
    run: echo hi
"#,
    )
    .unwrap();
    let mut refs: Vec<(String, String)> = workflow_output_references(&job)
        .into_iter()
        .map(|reference| (reference.call_job_id, reference.output))
        .collect();
    refs.sort();
    assert_eq!(
        refs,
        vec![
            ("build".to_string(), "ready".to_string()),
            ("other".to_string(), "value".to_string()),
            ("step-job".to_string(), "x".to_string()),
        ]
    );
}

// ── unit tests: posix_path ──────────────────────────────────────────────

#[test]
fn posix_normalize_resolves_dot_and_dot_dot_segments() {
    assert_eq!(
        posix_path::normalize(".github/workflows/./reusable.yml"),
        ".github/workflows/reusable.yml"
    );
    assert_eq!(
        posix_path::normalize(".github/workflows/../actions/reusable.yml"),
        ".github/actions/reusable.yml"
    );
    assert_eq!(posix_path::normalize("../outside.yml"), "../outside.yml");
    assert_eq!(posix_path::normalize(""), ".");
}

#[test]
fn posix_dirname_of_a_bare_basename_is_dot() {
    assert_eq!(
        posix_path::dirname(".github/workflows/ci.yml"),
        ".github/workflows"
    );
    assert_eq!(posix_path::dirname("ci.yml"), ".");
}

// ── model sanity: DiagnosticCode::as_str stays in sync with serde ───────

#[test]
fn diagnostic_code_as_str_matches_its_serde_wire_value() {
    for code in ALL_DIAGNOSTIC_CODES {
        let serialized = serde_json::to_value(code).unwrap();
        assert_eq!(
            serialized,
            serde_json::Value::String(code.as_str().to_string()),
            "{code:?}"
        );
    }
}

